const calc = $('Calculate Profit & Pack Items').first().json;
const trigger = $('Receive Dashboard Order').first().json;
const body = trigger.body || trigger;
return [{ json: {
  Action: body.action || body.Action || 'create',
  Customer_Name: calc.Customer_Name || '',
  Order_ID: calc.Order_ID || '',
  Order_Text: calc.Order_Text || '',
  Update_Note: body.Update_Note || '',
  Total_Revenue: calc.Total_Revenue || 0,
  Total_Cost: calc.Total_Cost || 0,
  Final_Profit: calc.Final_Profit || 0
}}];
